INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('HOOK_FORMULAS: Le hook "La plupart des gens pensent X, mais en realite Y" cree un pattern interrupt cognitif.', 'Hook: plupart pensent X mais Y = pattern interrupt', 'content', 'best_practice', 0.85, 'massive_boost_24', 'system'),
('HOOK_FORMULAS: Le hook "J ai teste X pendant 30 jours, voici ce qui s est passe" declenche la curiosite.', 'Hook: teste X 30 jours = curiosite', 'content', 'best_practice', 0.85, 'massive_boost_24', 'system'),
('HOOK_FORMULAS: Le hook "Arretez de faire X (faites Y a la place)" provoque un arret du scroll immediat.', 'Hook: arretez X faites Y = arret scroll', 'content', 'best_practice', 0.85, 'massive_boost_24', 'system'),
('HOOK_FORMULAS: Le hook numerique "3 erreurs qui vous coutent X€ par mois" combine chiffre + perte = engagement max.', 'Hook: X erreurs coutent Y€ = engagement max', 'content', 'best_practice', 0.88, 'massive_boost_24', 'system'),
('HOOK_FORMULAS: Le hook "Ce que [expert/marque connue] ne vous dit pas sur X" exploite l autorite + le secret.', 'Hook: ce que expert ne dit pas = autorite + secret', 'content', 'best_practice', 0.82, 'massive_boost_24', 'system'),
('HOOK_FORMULAS: Le hook question "Pourquoi 90% des [cible] echouent a [objectif]?" combine statistique + identification.', 'Hook: pourquoi 90% echouent = stats + identification', 'content', 'best_practice', 0.85, 'massive_boost_24', 'system'),
('HOOK_FORMULAS: Le hook "En 2026, si vous ne faites pas X, vous perdez Y" joue sur l urgence et la peur du retard.', 'Hook: en 2026 si pas X perdez Y = urgence', 'content', 'best_practice', 0.82, 'massive_boost_24', 'system'),
('HOOK_FORMULAS: Le hook controversial "X est mort (voici pourquoi)" genere des debats en commentaire et boost l algo.', 'Hook: X est mort = debat commentaires + algo boost', 'content', 'best_practice', 0.82, 'massive_boost_24', 'system'),
('CTA_FORMULAS: Le CTA "Telechargez votre guide gratuit" convertit 30% mieux que "En savoir plus" (specificite).', 'CTA specifique > generique: +30% conversion', 'content', 'insight', 0.85, 'massive_boost_24', 'system'),
('CTA_FORMULAS: Le CTA negatif "Non merci, je prefere perdre des clients" augmente les clics par peur de perte.', 'CTA negatif = clic par peur de perte', 'content', 'insight', 0.78, 'massive_boost_24', 'system'),
('CTA_FORMULAS: Le double CTA (primaire + secondaire plus soft) augmente la conversion totale de 20%.', 'Double CTA primaire + secondaire = +20% conversion totale', 'content', 'best_practice', 0.82, 'massive_boost_24', 'system'),
('CTA_FORMULAS: Le CTA avec countdown (il reste 2h pour profiter de -20%) triple les clics pendant la derniere heure.', 'CTA countdown = 3x clics derniere heure', 'content', 'insight', 0.82, 'massive_boost_24', 'system'),
('SUBJECT_LINE: Les subject lines < 40 caracteres ont le meilleur taux d ouverture sur mobile (preheader visible).', 'Subject line < 40 chars = meilleur mobile', 'email', 'best_practice', 0.85, 'massive_boost_24', 'system'),
('SUBJECT_LINE: L emoji dans le subject line augmente l ouverture de 4.5% en moyenne mais varie par secteur.', 'Emoji subject = +4.5% ouverture (varie par secteur)', 'email', 'insight', 0.80, 'massive_boost_24', 'system'),
('SUBJECT_LINE: Les subject lines qui posent une question ont 10% plus d ouvertures que les affirmatives.', 'Subject question = +10% ouverture vs affirmation', 'email', 'insight', 0.82, 'massive_boost_24', 'system'),
('SUBJECT_LINE: Le [Prenom], dans le subject line augmente l ouverture de 22%. A utiliser avec parcimonie.', '[Prenom] subject = +22% ouverture. Parcimonie', 'email', 'insight', 0.82, 'massive_boost_24', 'system'),
('SUBJECT_LINE: Les mots a eviter dans les subjects: gratuit, promo, offre speciale (declenchent le spam filter).', 'Eviter: gratuit, promo, offre speciale dans subject = spam', 'email', 'best_practice', 0.85, 'massive_boost_24', 'system'),
('SUBJECT_LINE: Le subject en lowercase (sans majuscule) parait plus personnel et augmente l ouverture de 6%.', 'Subject lowercase = +6% ouverture (plus personnel)', 'email', 'insight', 0.78, 'massive_boost_24', 'system'),
