('SAAS_ONBOARDING: Le NUX (New User Experience) doit etre optimise separement du reste de l app. C est le moment critique.', 'NUX (New User Experience) = moment critique, optimiser separement', 'onboarding', 'best_practice', 0.85, 'massive_boost_24', 'system'),
('DATA_PRIVACY: Le opt-in double (confirmation par email) est la meilleure pratique RGPD et ameliore la qualite de la liste de 30%.', 'Double opt-in = RGPD + qualite liste +30%', 'email', 'best_practice', 0.88, 'massive_boost_24', 'system'),
('DATA_PRIVACY: Le droit de portabilite RGPD: les clients peuvent demander un export de toutes leurs donnees.', 'RGPD portabilite: export donnees client obligatoire', 'ceo', 'best_practice', 0.88, 'massive_boost_24', 'system'),
('DATA_PRIVACY: Le consentement marketing doit etre separe du consentement technique. Pas de cases pre-cochees.', 'Consentement marketing separe. Pas pre-coche', 'ceo', 'best_practice', 0.90, 'massive_boost_24', 'system'),
('DATA_PRIVACY: La retention des donnees doit etre limitee dans le temps. Supprimer automatiquement apres X mois d inactivite.', 'Retention data limitee. Suppression auto apres inactivite', 'ceo', 'best_practice', 0.85, 'massive_boost_24', 'system'),
('ANALYTICS_SETUP: Google Analytics 4 est le standard. Configurer les evenements cles: signup, purchase, add_to_cart, begin_checkout.', 'GA4 + evenements cles: signup, purchase, cart, checkout', 'ceo', 'best_practice', 0.88, 'massive_boost_24', 'system'),
('ANALYTICS_SETUP: Le Google Tag Manager (GTM) centralise tous les tags marketing. 1 seul script au lieu de 10.', 'GTM = centraliser tous tags marketing', 'ceo', 'best_practice', 0.85, 'massive_boost_24', 'system'),
('ANALYTICS_SETUP: Les UTM parameters doivent suivre une convention coherente: utm_source, utm_medium, utm_campaign minimum.', 'UTM convention coherente: source, medium, campaign minimum', 'marketing', 'best_practice', 0.88, 'massive_boost_24', 'system'),
('ANALYTICS_SETUP: Les goals GA4 (objectifs) doivent etre configures AVANT le lancement. Pas apres (perte de donnees).', 'Goals GA4 = configurer avant lancement', 'ceo', 'best_practice', 0.88, 'massive_boost_24', 'system'),
('TESTING: Le A/B test ideal dure 2-4 semaines avec un minimum de 1000 conversions par variante pour etre significatif.', 'A/B test: 2-4 sem, 1000 conversions/variante', 'ceo', 'best_practice', 0.85, 'massive_boost_24', 'system'),
('TESTING: Ne tester qu une seule variable a la fois. Le multivariate testing necessite 10x plus de trafic.', 'A/B test: 1 variable. Multivariate = 10x trafic', 'ceo', 'best_practice', 0.88, 'massive_boost_24', 'system'),
('TESTING: Les tests sur le CTA (couleur, texte, position) ont le plus grand impact avec le moins d effort.', 'Test CTA = plus grand impact, moins effort', 'ceo', 'best_practice', 0.85, 'massive_boost_24', 'system'),
('TESTING: Le controle (version actuelle) doit toujours etre inclus dans le test. Ne jamais tester variante A vs variante B sans controle.', 'A/B test: toujours inclure controle (version actuelle)', 'ceo', 'best_practice', 0.85, 'massive_boost_24', 'system'),
('SUPPLY_CHAIN: Le dropshipping a des marges de 10-30% mais elimine le risque de stock. Ideal pour tester un marche.', 'Dropshipping: 10-30% marge, 0 risque stock. Test marche', NULL, 'insight', 0.78, 'massive_boost_24', 'system'),
('SUPPLY_CHAIN: Le sourcing direct (fabricant → vendeur) augmente les marges de 40-60% vs les intermediaires.', 'Sourcing direct fabricant = +40-60% marge vs intermediaires', NULL, 'insight', 0.80, 'massive_boost_24', 'system'),
('SUPPLY_CHAIN: Le stock de securite ideal: 2 semaines de ventes moyennes. Ni trop (cash immobilise) ni trop peu (rupture).', 'Stock securite = 2 semaines ventes moyennes', NULL, 'best_practice', 0.80, 'massive_boost_24', 'system'),
('FRANCHISE: Le franchiseur doit fournir un DIP (Document d Information Precontractuel) 20 jours avant la signature.', 'Franchise DIP: 20 jours avant signature', NULL, 'insight', 0.80, 'massive_boost_24', 'system'),
('FRANCHISE: Le droit d entree moyen pour une franchise en France: 10K-50K€ selon le secteur et la notoriete.', 'Franchise France: droit entree 10K-50K€', NULL, 'insight', 0.78, 'massive_boost_24', 'system'),
('EXPORT: Les aides a l export (BPI, Business France) couvrent 50% des frais de prospection internationale.', 'Aides export BPI/BF = 50% frais prospection internationale', 'comptable', 'insight', 0.78, 'massive_boost_24', 'system'),
('EXPORT: La TVA intracommunautaire (B2B UE) est autoliquide par le client. Pas besoin de la facturer.', 'TVA intra-UE B2B: autoliquidation client', 'comptable', 'insight', 0.85, 'massive_boost_24', 'system'),
('CROWDFUNDING: Les campagnes Kickstarter avec video lèvent 4x plus que celles sans video.', 'Kickstarter video = 4x levee vs sans', NULL, 'insight', 0.82, 'massive_boost_24', 'system'),
('CROWDFUNDING: Le early bird pricing (premiers backers = prix reduit) genere 40% du financement dans les premieres 48h.', 'Early bird crowdfunding = 40% financement 48h', NULL, 'insight', 0.80, 'massive_boost_24', 'system'),
('STARTUP_FRANCE: Le statut SAS est le plus adapte pour lever des fonds et accueillir des investisseurs.', 'SAS = meilleur statut levee de fonds France', 'ceo', 'insight', 0.85, 'massive_boost_24', 'system'),
('STARTUP_FRANCE: Les incubateurs (Station F, Agoranov) offrent du mentorat + reseau + parfois du financement.', 'Incubateurs France: mentorat + reseau + financement', 'ceo', 'insight', 0.80, 'massive_boost_24', 'system'),
('STARTUP_FRANCE: La BPI (Banque Publique d Investissement) offre des prets d honneur (0% interet) jusqu a 60K€.', 'BPI prets honneur 0% jusqu a 60K€', 'comptable', 'insight', 0.82, 'massive_boost_24', 'system'),
('STARTUP_FRANCE: Le CAPE (Contrat d Appui au Projet d Entreprise) permet de tester son activite tout en gardant ses allocations.', 'CAPE = tester activite + garder allocations', 'ceo', 'insight', 0.78, 'massive_boost_24', 'system'),
('STARTUP_FRANCE: L ACRE (Aide a la Creation) exonere partiellement les charges sociales la premiere annee.', 'ACRE = exoneration charges sociales an 1', 'comptable', 'insight', 0.82, 'massive_boost_24', 'system'),
('INVESTOR: Les investisseurs regardent d abord l equipe (50%), puis le marche (30%), puis le produit (20%).', 'Investisseurs: equipe 50%, marche 30%, produit 20%', 'ceo', 'insight', 0.85, 'massive_boost_24', 'system'),
('INVESTOR: Le deck de 10 slides (Sequoia format): Problem, Solution, Why Now, Market, Product, Team, Business Model, Traction, Ask.', 'Deck Sequoia 10 slides: Problem → Ask', 'ceo', 'best_practice', 0.82, 'massive_boost_24', 'system'),
('INVESTOR: La traction est le facteur #1 de decision. MRR en croissance de 15-20% par mois = signal fort.', 'Traction = facteur #1. MRR +15-20%/mois = signal fort', 'ceo', 'insight', 0.88, 'massive_boost_24', 'system'),
('INVESTOR: Les valorisations seed en France (2026): 1-3M€ pre-revenue, 3-8M€ avec traction.', 'Seed France 2026: 1-3M pre-revenue, 3-8M avec traction', 'ceo', 'insight', 0.78, 'massive_boost_24', 'system'),
('INVESTOR: Le cap table (tableau de capitalisation) doit etre propre. Les fondateurs doivent garder > 50% apres le seed.', 'Cap table: fondateurs > 50% post-seed', 'ceo', 'best_practice', 0.82, 'massive_boost_24', 'system')
INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('PROMPT_ENGINEERING: Le role prompting (Tu es un expert en X) augmente la qualite des reponses IA de 30%.', 'Role prompting expert = +30% qualite IA', 'ceo', 'best_practice', 0.88, 'massive_boost_25', 'system'),
('PROMPT_ENGINEERING: Le few-shot prompting (3-5 exemples dans le prompt) ameliore la coherence des outputs de 50%.', 'Few-shot 3-5 exemples = +50% coherence', 'ceo', 'best_practice', 0.88, 'massive_boost_25', 'system'),
('PROMPT_ENGINEERING: Le chain-of-thought prompting (etape par etape) ameliore le raisonnement de l IA de 40%.', 'Chain-of-thought = +40% raisonnement IA', 'ceo', 'insight', 0.88, 'massive_boost_25', 'system'),
('PROMPT_ENGINEERING: Les contraintes negatives (ne fais PAS X) sont aussi importantes que les positives dans un prompt.', 'Contraintes negatives prompt = aussi importantes que positives', 'ceo', 'best_practice', 0.82, 'massive_boost_25', 'system'),
('PROMPT_ENGINEERING: Le temperature setting: 0 pour les taches precises, 0.7 pour la creativite, 1.0 pour le brainstorming.', 'Temperature IA: 0 precis, 0.7 creatif, 1.0 brainstorm', 'ceo', 'best_practice', 0.85, 'massive_boost_25', 'system'),
('AGENT_DESIGN: Chaque agent doit avoir un scope clair et limite. Un agent qui fait tout fait rien de bien.', 'Agent scope clair et limite = performance', 'ceo', 'best_practice', 0.92, 'massive_boost_25', 'system'),
('AGENT_DESIGN: Le contexte injecte dans le prompt de l agent doit etre concis. Trop de contexte = hallucination.', 'Contexte agent: concis. Trop = hallucination', 'ceo', 'best_practice', 0.88, 'massive_boost_25', 'system'),
