('INNOVATION_PRODUIT: Le feature flag (activer/desactiver une feature par segment) permet de tester sans risque.', 'Feature flag = test sans risque par segment', 'ceo', 'best_practice', 0.85, 'massive_boost_25', 'system'),
('INNOVATION_PRODUIT: Le Kano model classe les features en: must-have, performance, delighters. Focus sur les delighters pour se differencier.', 'Kano: must-have, performance, delighters. Focus delighters', 'ceo', 'best_practice', 0.82, 'massive_boost_25', 'system')
INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('MICRO_SAAS: Les micro-SaaS (1-2 personnes, niche, < 50K MRR) sont les plus rentables par employe.', 'Micro-SaaS = plus rentable par employe', 'ceo', 'insight', 0.80, 'massive_boost_26', 'system'),
('MICRO_SAAS: La distribution via les app stores (Shopify, WordPress plugins) donne acces a des millions de clients.', 'App stores distribution = millions clients potentiels', 'ceo', 'insight', 0.80, 'massive_boost_26', 'system'),
('MICRO_SAAS: Le bootstrap (auto-financement) est viable pour les micro-SaaS. Pas besoin de lever des fonds.', 'Bootstrap micro-SaaS = viable sans levee', 'ceo', 'insight', 0.82, 'massive_boost_26', 'system'),
('API_ECONOMY: Les APIs generent 50% des revenus d Amazon. L API-first approach ouvre des revenus B2B.', 'API economy: 50% revenus Amazon. API-first = B2B', 'ceo', 'insight', 0.80, 'massive_boost_26', 'system'),
('API_ECONOMY: La documentation API (Swagger/OpenAPI) claire est le facteur #1 d adoption par les developpeurs.', 'Doc API claire = facteur #1 adoption dev', 'ceo', 'best_practice', 0.85, 'massive_boost_26', 'system'),
('PLATFORM: Les plateformes (marketplace, API ecosystem) creent un moat par l effet reseau. Chaque participant ajoute de la valeur.', 'Platform = moat effet reseau. Plus de participants = plus de valeur', 'ceo', 'insight', 0.85, 'massive_boost_26', 'system'),
('PLATFORM: Le flywheel (volant d inertie) d Amazon: plus de vendeurs → plus de choix → plus d acheteurs → plus de vendeurs.', 'Flywheel Amazon: vendeurs → choix → acheteurs → vendeurs', 'ceo', 'insight', 0.85, 'massive_boost_26', 'system'),
('PLATFORM: Le tipping point d une plateforme: quand la croissance organique depasse l acquisition payante.', 'Platform tipping point: croissance organique > acquisition payante', 'ceo', 'insight', 0.82, 'massive_boost_26', 'system'),
('B2B_SALES: Le decision-making unit (DMU) en B2B implique 6-10 personnes. Identifier et convaincre chaque stakeholder.', 'DMU B2B: 6-10 personnes. Convaincre chaque stakeholder', 'commercial', 'insight', 0.85, 'massive_boost_26', 'system'),
('B2B_SALES: Le business case ROI (document montrant le retour sur investissement) accelere la decision d achat de 40%.', 'Business case ROI = -40% cycle decision B2B', 'commercial', 'best_practice', 0.85, 'massive_boost_26', 'system'),
('B2B_SALES: La preuve de concept (POC) gratuite de 2-4 semaines convertit 50% des prospects enterprise.', 'POC gratuit 2-4 sem = 50% conversion enterprise', 'commercial', 'insight', 0.82, 'massive_boost_26', 'system'),
('B2B_SALES: Le security review (SOC 2, pentest report) est demande par 70% des prospects mid-market/enterprise.', 'Security review = demande 70% mid-market/enterprise', 'commercial', 'insight', 0.82, 'massive_boost_26', 'system'),
('B2B_SALES: Les case studies par industrie (SaaS, ecommerce, agence) sont les outils de vente les plus efficaces en B2B.', 'Case studies par industrie = outil vente #1 B2B', 'commercial', 'best_practice', 0.88, 'massive_boost_26', 'system'),
('UPSELL: Le moment optimal pour proposer un upsell: quand le client atteint 80% de son quota d utilisation.', 'Upsell optimal: client a 80% quota', 'retention', 'best_practice', 0.85, 'massive_boost_26', 'system'),
('UPSELL: Les annual plans offerts avec un discount de 17% (2 mois gratuits) convertissent 30% des clients mensuels.', 'Annual plan 17% discount = 30% conversion mensuel → annuel', 'retention', 'insight', 0.82, 'massive_boost_26', 'system'),
('UPSELL: L add-on a la carte (feature supplementaire a X€/mois) est moins intimidant qu un upgrade de plan complet.', 'Add-on a la carte < intimidant que upgrade plan', 'retention', 'insight', 0.80, 'massive_boost_26', 'system'),
('UPSELL: Le timing du upsell: jamais pendant une plainte ou un bug. Attendre un moment de satisfaction (apres un succes).', 'Upsell: jamais pendant plainte. Apres succes', 'retention', 'best_practice', 0.88, 'massive_boost_26', 'system'),
('UPSELL: Le cross-sell (proposer un produit complementaire) a un taux de conversion de 20-30% quand il est pertinent.', 'Cross-sell pertinent = 20-30% conversion', 'retention', 'insight', 0.82, 'massive_boost_26', 'system'),
('CHURN_PREVENTION: Les 3 signaux de pre-churn: baisse d utilisation, pas de login depuis 7 jours, ticket support non resolu.', 'Pre-churn: baisse usage + 7j sans login + ticket ouvert', 'retention', 'insight', 0.88, 'massive_boost_26', 'system'),
('CHURN_PREVENTION: L email de winback avec une offre (1 mois gratuit ou 30% off) recupere 10-15% des churners.', 'Email winback + offre = 10-15% recuperation churners', 'retention', 'best_practice', 0.82, 'massive_boost_26', 'system'),
('CHURN_PREVENTION: Le exit survey (pourquoi partez-vous?) en 1 question donne les insights les plus actionables.', 'Exit survey 1 question = insights actionables churn', 'retention', 'best_practice', 0.85, 'massive_boost_26', 'system'),
('CHURN_PREVENTION: Le pause subscription (au lieu d annuler) retient 20% des clients qui auraient churne.', 'Pause subscription = retenir 20% pre-churners', 'retention', 'insight', 0.82, 'massive_boost_26', 'system'),
('CHURN_PREVENTION: Le downgrade path (plan inferieur au lieu d annuler) sauve 15% des clients qui veulent partir.', 'Downgrade path = sauver 15% pre-churners', 'retention', 'insight', 0.82, 'massive_boost_26', 'system'),
('EMAIL_DELIVERABILITY: Le SPF, DKIM et DMARC doivent etre configures pour eviter le spam. Verifier avec mail-tester.com.', 'SPF+DKIM+DMARC = eviter spam. Tester mail-tester.com', 'email', 'best_practice', 0.92, 'massive_boost_26', 'system'),
('EMAIL_DELIVERABILITY: Le warmup d un nouveau domaine email: commencer par 20 emails/jour, augmenter de 20% par semaine.', 'Warmup domaine: 20/jour +20%/semaine', 'email', 'best_practice', 0.85, 'massive_boost_26', 'system'),
('EMAIL_DELIVERABILITY: Le bounce rate doit etre < 2%. Au-dessus, nettoyer la liste immediatement.', 'Bounce rate < 2%. Au-dessus = nettoyer liste', 'email', 'best_practice', 0.88, 'massive_boost_26', 'system'),
('EMAIL_DELIVERABILITY: Le spam complaint rate doit etre < 0.1%. Au-dessus, le domaine risque d etre blackliste.', 'Spam complaint < 0.1%. Sinon blacklist domaine', 'email', 'best_practice', 0.90, 'massive_boost_26', 'system'),
('EMAIL_DELIVERABILITY: Les listes achetees ont un bounce rate de 20-40% et detruisent la reputation du domaine.', 'Listes achetees = 20-40% bounce. Detruisent reputation', 'email', 'insight', 0.90, 'massive_boost_26', 'system'),
('SOCIAL_PROOF: Les logos clients (comme vu dans...) augmentent la credibilite de 40% sur les landing pages.', 'Logos clients landing = +40% credibilite', 'commercial', 'insight', 0.85, 'massive_boost_26', 'system'),
('SOCIAL_PROOF: Le nombre de clients (rejoint par 10 000+ entrepreneurs) est le social proof le plus impactant.', 'Nombre clients (10K+ entrepreneurs) = social proof #1', 'commercial', 'insight', 0.85, 'massive_boost_26', 'system'),
('SOCIAL_PROOF: Les ratings en temps reel (4.8/5 sur 500 avis) sont plus persuasifs que les temoignages individuels.', 'Rating temps reel 4.8/5 500 avis > temoignages individuels', 'commercial', 'insight', 0.82, 'massive_boost_26', 'system'),
('SOCIAL_PROOF: Les awards et certifications (Top 10 SaaS 2026, Certified Partner) augmentent la conversion de 15%.', 'Awards certifications = +15% conversion', 'commercial', 'insight', 0.78, 'massive_boost_26', 'system'),
('SOCIAL_PROOF: Le FOMO counter (327 personnes ont achete cette semaine) augmente les achats impulsifs de 20%.', 'FOMO counter = +20% achats impulsifs', 'commercial', 'insight', 0.78, 'massive_boost_26', 'system'),
('PARTNERSHIP_STRATEGY: Les partenariats technologiques (integration avec un outil populaire) generent des leads qualifies a cout nul.', 'Integration partenaire tech = leads qualifies cout 0', 'ceo', 'insight', 0.82, 'massive_boost_26', 'system'),
('PARTNERSHIP_STRATEGY: Le co-webinaire (avec un partenaire complementaire) double l audience et divise les couts.', 'Co-webinaire partenaire = 2x audience, /2 couts', 'marketing', 'best_practice', 0.82, 'massive_boost_26', 'system'),
('PARTNERSHIP_STRATEGY: Les referral partnerships (commission mutuelle) generent 15-25% des leads pour les SaaS matures.', 'Referral partnerships = 15-25% leads SaaS mature', 'marketing', 'insight', 0.82, 'massive_boost_26', 'system'),
('PARTNERSHIP_STRATEGY: Le guest blogging (article invite sur un blog partenaire) genere des backlinks SEO + leads.', 'Guest blogging = backlinks SEO + leads', 'seo', 'best_practice', 0.80, 'massive_boost_26', 'system'),
('PARTNERSHIP_STRATEGY: Les joint case studies (avec un client commun) sont les plus credibles et generent le plus de leads.', 'Joint case study = plus credible + max leads', 'marketing', 'best_practice', 0.80, 'massive_boost_26', 'system'),
('CONTENT_DISTRIBUTION: La regle 20/80 du contenu: passer 20% du temps a creer, 80% a distribuer.', 'Contenu: 20% creation, 80% distribution', 'content', 'best_practice', 0.85, 'massive_boost_26', 'system'),
('CONTENT_DISTRIBUTION: Le cross-posting adapte (meme message, format different par plateforme) maximise la portee.', 'Cross-posting adapte par plateforme = max portee', 'content', 'best_practice', 0.85, 'massive_boost_26', 'system'),
('CONTENT_DISTRIBUTION: Les communautes de niche (Discord, Slack, Reddit) sont des canaux de distribution sous-exploites.', 'Communautes niche = canaux distribution sous-exploites', 'content', 'insight', 0.82, 'massive_boost_26', 'system'),
('CONTENT_DISTRIBUTION: Le employee advocacy (employes qui partagent le contenu) multiplie la portee par le nombre d employes.', 'Employee advocacy = portee × nombre employes', 'content', 'insight', 0.80, 'massive_boost_26', 'system'),
('CONTENT_DISTRIBUTION: Le paid amplification (booster les meilleurs posts organiques) a un ROI 3x superieur aux ads creees de zero.', 'Booster meilleur organique = 3x ROI vs ads from scratch', 'ads', 'insight', 0.82, 'massive_boost_26', 'system'),
('SOCIAL_COMMERCE: Le live shopping (vente en direct sur les reseaux) a un taux de conversion de 10-30% en Asie. Emerge en Europe.', 'Live shopping = 10-30% conversion Asie. Emerge Europe', NULL, 'insight', 0.78, 'massive_boost_26', 'system'),
('SOCIAL_COMMERCE: Le shoppable content (achat direct depuis un post) sera standard sur IG, TikTok et Pinterest en 2026.', 'Shoppable content standard IG/TikTok/Pinterest 2026', NULL, 'insight', 0.82, 'massive_boost_26', 'system'),
('SOCIAL_COMMERCE: Les reviews video (unboxing, test produit) generent 4x plus de confiance que les reviews texte.', 'Reviews video = 4x confiance vs texte', NULL, 'insight', 0.85, 'massive_boost_26', 'system'),
('SOCIAL_COMMERCE: Le social proof en direct (X personnes regardent ce produit en ce moment) augmente l urgence de 25%.', 'Social proof temps reel = +25% urgence', 'commercial', 'insight', 0.78, 'massive_boost_26', 'system'),
('SOCIAL_COMMERCE: Les catalogues Instagram Shop avec prix et description augmentent les ventes directes de 30%.', 'IG Shop catalogue = +30% ventes directes', NULL, 'insight', 0.80, 'massive_boost_26', 'system'),
('FINOPS: Les couts cloud (AWS, GCP, Vercel) doivent etre monitores quotidiennement. Les surprises de facturation sont courantes.', 'Couts cloud: monitoring quotidien. Surprises courantes', 'comptable', 'best_practice', 0.85, 'massive_boost_26', 'system'),
('FINOPS: Le reserved capacity (engagement annuel) reduit les couts cloud de 30-50%.', 'Reserved capacity cloud = -30-50% couts', 'comptable', 'insight', 0.82, 'massive_boost_26', 'system'),
('FINOPS: Les serverless functions (Vercel, Cloudflare) sont cost-effective jusqu a 10M requetes/mois. Au-dela, evaluer les VPS.', 'Serverless cost-effective < 10M req/mois', 'comptable', 'insight', 0.80, 'massive_boost_26', 'system'),
('FINOPS: Le cout d un SaaS par utilisateur doit baisser avec l echelle (economies d echelle). Si ca augmente = architecture a revoir.', 'Cout/user doit baisser avec scale. Sinon revoir archi', 'comptable', 'insight', 0.82, 'massive_boost_26', 'system'),
('LEGAL_SAAS: Les CGU SaaS doivent couvrir: propriete des donnees, uptime SLA, politique de remboursement, limitation de responsabilite.', 'CGU SaaS: data ownership, SLA, remboursement, limitation responsabilite', 'ceo', 'best_practice', 0.85, 'massive_boost_26', 'system'),
('LEGAL_SAAS: Le SLA (Service Level Agreement) standard pour un SaaS: 99.9% uptime = 8.76h de downtime max par an.', 'SLA 99.9% = 8.76h downtime max/an', 'ceo', 'insight', 0.85, 'massive_boost_26', 'system'),
('LEGAL_SAAS: La clause de propriete intellectuelle doit preciser que les donnees du client lui appartiennent. Le SaaS est un service.', 'PI: donnees client = propriete client. SaaS = service', 'ceo', 'best_practice', 0.88, 'massive_boost_26', 'system'),
('LEGAL_SAAS: Le droit de suppression des donnees (RGPD article 17) doit etre implementable en < 30 jours.', 'Suppression donnees RGPD < 30 jours', 'ceo', 'best_practice', 0.88, 'massive_boost_26', 'system'),
('OBSERVABILITY: Les 3 piliers de l observabilite: logs, metriques, traces. Les 3 sont necessaires pour debugger en production.', 'Observabilite: logs + metriques + traces = debug prod', 'ceo', 'best_practice', 0.85, 'massive_boost_26', 'system'),
('OBSERVABILITY: Les alertes doivent etre actionnables. Une alerte qui n est pas actionnee = du bruit a supprimer.', 'Alertes actionnables. Non actionnees = bruit, supprimer', 'ceo', 'best_practice', 0.85, 'massive_boost_26', 'system'),
('OBSERVABILITY: Le error budget (SLI/SLO): definir combien d erreurs sont acceptables avant d arreter les releases.', 'Error budget SLI/SLO: erreurs acceptables avant stop releases', 'ceo', 'best_practice', 0.82, 'massive_boost_26', 'system'),
('OBSERVABILITY: Le health check endpoint (/health) est obligatoire pour le monitoring automatise et les load balancers.', 'Health check /health = obligatoire monitoring + LB', 'ceo', 'best_practice', 0.88, 'massive_boost_26', 'system'),
('DATABASE: Les index SQL sur les colonnes WHERE et JOIN reduisent les temps de requete de 10-100x.', 'Index SQL WHERE/JOIN = 10-100x acceleration', 'ceo', 'best_practice', 0.90, 'massive_boost_26', 'system'),
('DATABASE: Le connection pooling (PgBouncer, Supabase pooler) est obligatoire pour les apps serverless.', 'Connection pooling = obligatoire serverless', 'ceo', 'best_practice', 0.88, 'massive_boost_26', 'system'),
('DATABASE: Les migrations doivent etre reversibles. Chaque UP doit avoir un DOWN pour rollback en cas de probleme.', 'Migrations reversibles: UP + DOWN pour rollback', 'ceo', 'best_practice', 0.85, 'massive_boost_26', 'system'),
('DATABASE: Le RLS (Row Level Security) de Supabase est le moyen le plus securise de proteger les donnees multi-tenant.', 'RLS Supabase = securite multi-tenant #1', 'ceo', 'best_practice', 0.90, 'massive_boost_26', 'system'),
('DATABASE: Les requetes N+1 (1 requete par item au lieu de 1 requete batch) sont le piege de performance #1.', 'N+1 queries = piege performance #1. Batch', 'ceo', 'best_practice', 0.88, 'massive_boost_26', 'system')
INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
