('JURIDIQUE_FR: La protection des donnees (CNIL) impose une declaration des traitements et un DPO pour les entreprises > 250.', 'CNIL: declaration traitements. DPO > 250 employes', 'ceo', 'best_practice', 0.85, 'massive_boost_28', 'system'),
('GROWTH_FR: Le bouche-a-oreille est le canal #1 de decouverte en France (63% des decisions d achat).', 'Bouche-a-oreille FR = #1 canal 63% decisions achat', 'marketing', 'insight', 0.85, 'massive_boost_28', 'system'),
('GROWTH_FR: Les avis clients sont consultes par 87% des Francais avant un achat en ligne.', 'Avis clients FR: 87% consultent avant achat online', 'marketing', 'insight', 0.88, 'massive_boost_28', 'system'),
('GROWTH_FR: Le marketing d influence est le canal en plus forte croissance en France (+25%/an).', 'Influence marketing FR +25%/an = plus forte croissance', 'marketing', 'insight', 0.80, 'massive_boost_28', 'system'),
('GROWTH_FR: Les Francais sont sensibles au prix mais aussi a la qualite. Le rapport qualite-prix est le critere #1.', 'FR: rapport qualite-prix = critere #1', 'marketing', 'insight', 0.85, 'massive_boost_28', 'system'),
('GROWTH_FR: Le marche des freelances en France croit de 20%/an. KeiroAI peut cibler ce segment de 1.5M de personnes.', 'Freelances FR: 1.5M personnes, +20%/an. Cible KeiroAI', 'ceo', 'insight', 0.80, 'massive_boost_28', 'system'),
('KEIROAI_FR: KeiroAI doit adapter son ton au marche francophone: professionnel mais accessible, pas trop corporate.', 'KeiroAI FR: ton professionnel + accessible', 'ceo', 'best_practice', 0.90, 'massive_boost_28', 'system'),
('KEIROAI_FR: Les agents KeiroAI doivent generer du contenu en francais impeccable (grammaire, accents, expressions).', 'KeiroAI agents: francais impeccable obligatoire', NULL, 'best_practice', 0.92, 'massive_boost_28', 'system'),
('KEIROAI_FR: Le marche cible initial de KeiroAI: France + Belgique + Suisse + Canada francophone = 80M francophones.', 'KeiroAI cible: FR+BE+CH+CA = 80M francophones', 'ceo', 'insight', 0.85, 'massive_boost_28', 'system'),
('KEIROAI_FR: Les PME francaises (3.9M d entreprises) sont sous-equipees en outils IA marketing. Opportunite massive.', 'PME FR 3.9M sous-equipees IA marketing. Opportunite', 'ceo', 'insight', 0.85, 'massive_boost_28', 'system'),
('KEIROAI_FR: Le positionnement KeiroAI pour le marche FR: l equipe marketing IA complete, pas juste un outil de plus.', 'KeiroAI FR: equipe marketing IA complete, pas 1 outil de plus', 'ceo', 'best_practice', 0.92, 'massive_boost_28', 'system')
INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('COMMERCE_LOCAL: Le click-and-mortar (presence physique + en ligne) est le modele le plus resilient pour le retail local.', 'Click-and-mortar = retail local resilient', NULL, 'insight', 0.82, 'massive_boost_29', 'system'),
('COMMERCE_LOCAL: Les programmes de fidelite avec application mobile ont 4x plus d utilisation que les cartes physiques.', 'App fidelite = 4x utilisation vs carte physique', NULL, 'insight', 0.82, 'massive_boost_29', 'system'),
('COMMERCE_LOCAL: Le WiFi gratuit en boutique avec portail captif (email pour se connecter) collecte 20% d emails en plus.', 'WiFi gratuit portail captif = +20% emails', NULL, 'insight', 0.78, 'massive_boost_29', 'system'),
('COMMERCE_LOCAL: La livraison locale en velo/scooter (rayon 5km) est plus rapide et moins chere que les transporteurs nationaux.', 'Livraison locale velo = plus rapide et moins cher', NULL, 'insight', 0.78, 'massive_boost_29', 'system'),
('COMMERCE_LOCAL: Les marches locaux et pop-up stores generent 40% plus de ventes au m2 que les boutiques permanentes.', 'Pop-up stores = +40% ventes/m2 vs permanent', NULL, 'insight', 0.78, 'massive_boost_29', 'system'),
('MINDSET: La regle des 10 000 heures (Malcolm Gladwell) pour atteindre l expertise. La perseverance bat le talent.', '10 000h expertise. Perseverance > talent', 'ceo', 'insight', 0.78, 'massive_boost_29', 'system'),
('MINDSET: Le growth mindset (Carol Dweck): croire que les competences se developpent = performances superieures de 20%.', 'Growth mindset = +20% performances (Dweck)', 'ceo', 'insight', 0.80, 'massive_boost_29', 'system'),
('MINDSET: Le biais de survie: on ne voit que les succes, pas les echecs. 90% des startups echouent mais on ne les voit pas.', 'Biais survie: 90% startups echouent mais invisibles', 'ceo', 'insight', 0.82, 'massive_boost_29', 'system'),
('MINDSET: L iteration rapide (fail fast, learn faster) est la competence #1 des fondateurs qui reussissent.', 'Fail fast learn faster = competence #1 fondateurs', 'ceo', 'insight', 0.85, 'massive_boost_29', 'system'),
('MINDSET: Le stoicisme entrepreneurial: controler ce qu on peut (produit, effort), accepter ce qu on ne peut pas (marche, timing).', 'Stoicisme: controler produit/effort, accepter marche/timing', 'ceo', 'insight', 0.78, 'massive_boost_29', 'system'),
('BENCHMARK_SAAS: Le benchmark CAC par canal: SEO 50-200€, Paid Ads 100-500€, Referral 20-50€, Content Marketing 50-150€.', 'CAC par canal: SEO 50-200, Ads 100-500, Referral 20-50, Content 50-150', 'ceo', 'insight', 0.80, 'massive_boost_29', 'system'),
('BENCHMARK_SAAS: Le taux d essai-a-client (trial-to-paid) moyen SaaS: 15-25% avec carte, 2-5% sans carte.', 'Trial-to-paid: 15-25% avec CB, 2-5% sans CB', 'ceo', 'insight', 0.85, 'massive_boost_29', 'system'),
('BENCHMARK_SAAS: Le churn annuel acceptable: < 5% pour enterprise, < 10% pour mid-market, < 15% pour SMB.', 'Churn annuel: < 5% enterprise, < 10% mid, < 15% SMB', 'ceo', 'insight', 0.85, 'massive_boost_29', 'system'),
('BENCHMARK_SAAS: Le time-to-value moyen pour les meilleurs SaaS: < 5 minutes. Pour KeiroAI: premier agent actif < 2 min.', 'TTV top SaaS < 5 min. KeiroAI < 2 min agent actif', 'onboarding', 'best_practice', 0.88, 'massive_boost_29', 'system'),
('BENCHMARK_SAAS: Le NPS benchmark SaaS: < 0 = alarme, 0-30 = ok, 30-50 = bon, 50-70 = excellent, > 70 = world class.', 'NPS SaaS: <0 alarme, 0-30 ok, 30-50 bon, 50-70 excellent, >70 world class', 'ceo', 'insight', 0.82, 'massive_boost_29', 'system'),
('OUTREACH_TOOLS: Apollo.io est l outil #1 pour le cold email B2B: base de donnees + sequences + tracking.', 'Apollo.io = #1 cold email B2B: DB + sequences + tracking', 'commercial', 'insight', 0.80, 'massive_boost_29', 'system'),
('OUTREACH_TOOLS: PhantomBuster automatise le scraping et l outreach LinkedIn. Attention aux limites LinkedIn (100 actions/jour).', 'PhantomBuster: scraping + outreach LinkedIn. Max 100 actions/jour', 'commercial', 'insight', 0.78, 'massive_boost_29', 'system'),
('OUTREACH_TOOLS: Lemlist est le meilleur outil de cold email avec images personnalisees (nom du prospect dans l image).', 'Lemlist = cold email + images personnalisees', 'email', 'insight', 0.78, 'massive_boost_29', 'system'),
('OUTREACH_TOOLS: La Grosse Newsletter (base de 500K emails) est une plateforme de sponsoring newsletter FR populaire.', 'La Grosse Newsletter = sponsoring newsletter FR 500K emails', 'email', 'insight', 0.75, 'massive_boost_29', 'system'),
('OUTREACH_TOOLS: Le warmup email (Mailwarm, Lemwarm) est obligatoire avant de lancer des cold emails. 2-4 semaines de warmup.', 'Email warmup obligatoire 2-4 semaines avant cold', 'email', 'best_practice', 0.85, 'massive_boost_29', 'system'),
('TIKTOK_STRATEGY: Le format POV (Point of View) est le plus viral sur TikTok. Se mettre dans la peau du client.', 'TikTok POV = format le plus viral. Perspective client', 'tiktok_comments', 'best_practice', 0.82, 'massive_boost_29', 'system'),
('TIKTOK_STRATEGY: Les transitions (avant/apres, transformation) obtiennent 3x plus de completions car les viewers attendent le resultat.', 'TikTok transitions = 3x completions (attente resultat)', 'tiktok_comments', 'insight', 0.85, 'massive_boost_29', 'system'),
('TIKTOK_STRATEGY: Les sons trending doivent etre utilises dans les 48h apres leur emergence. Apres = trop tard.', 'TikTok sons trending: utiliser dans 48h sinon trop tard', 'tiktok_comments', 'best_practice', 0.82, 'massive_boost_29', 'system'),
('TIKTOK_STRATEGY: Le green screen (fond personnalise) est le format le plus facile pour les debutants TikTok.', 'TikTok green screen = plus facile pour debutants', 'tiktok_comments', 'best_practice', 0.78, 'massive_boost_29', 'system'),
('TIKTOK_STRATEGY: Les TikTok Lives avec Q&A generent 10x plus de followers que les videos classiques.', 'TikTok Lives Q&A = 10x followers vs videos classiques', 'tiktok_comments', 'insight', 0.80, 'massive_boost_29', 'system'),
('REELS_STRATEGY: Le hook visuel (mouvement, couleur vive, texte anime) dans les 2 premieres secondes = +40% retention.', 'Reels hook visuel 2s = +40% retention', 'content', 'best_practice', 0.85, 'massive_boost_29', 'system'),
('REELS_STRATEGY: Les Reels educatifs (3 astuces pour X) sont les plus sauvegardes sur Instagram.', 'Reels educatifs 3 astuces = plus sauvegardes IG', 'content', 'insight', 0.82, 'massive_boost_29', 'system'),
('REELS_STRATEGY: Le format talking head (parler face camera) + sous-titres est le plus authentique et le plus engageant.', 'Reels talking head + sous-titres = authentique + engageant', 'content', 'best_practice', 0.82, 'massive_boost_29', 'system'),
('REELS_STRATEGY: La musique originale (pas de copyright) permet la monetisation et evite les suppressions.', 'Reels musique originale = monetisation + pas suppression', 'content', 'best_practice', 0.82, 'massive_boost_29', 'system'),
('REELS_STRATEGY: Les Reels reposts (re-partager un Reel performant) augmentent la portee sans effort supplementaire.', 'Reels repost = portee sans effort supplementaire', 'content', 'insight', 0.78, 'massive_boost_29', 'system'),
('INSTAGRAM_STORIES: Les stories avec stickers interactifs (question, poll, slider) ont 3x plus d interactions.', 'Stories stickers interactifs = 3x interactions', 'content', 'best_practice', 0.85, 'massive_boost_29', 'system'),
('INSTAGRAM_STORIES: Poster 3-7 stories par jour est optimal. Au-dela le taux de completion chute.', 'Stories: 3-7/jour optimal. Au-dela completion chute', 'content', 'best_practice', 0.82, 'massive_boost_29', 'system'),
('INSTAGRAM_STORIES: Les stories highlights (a la une) servent de mini-site web. Organiser par theme: FAQ, Temoignages, Offres.', 'Highlights = mini-site. FAQ + Temoignages + Offres', 'content', 'best_practice', 0.85, 'massive_boost_29', 'system'),
('INSTAGRAM_STORIES: Le swipe-up (lien) est disponible pour tous les comptes. Toujours ajouter un CTA avec lien.', 'Stories swipe-up tous comptes. CTA + lien toujours', 'content', 'best_practice', 0.82, 'massive_boost_29', 'system'),
('INSTAGRAM_STORIES: Les stories behind-the-scenes (bureau, equipe, processus) humanisent la marque et creent de la proximite.', 'Stories BTS = humaniser marque + proximite', 'content', 'best_practice', 0.82, 'massive_boost_29', 'system'),
('LINKEDIN_CONTENT: Les posts avec une opinion forte (je pense que X est faux) generent 5x plus de commentaires.', 'LinkedIn opinion forte = 5x commentaires', 'content', 'insight', 0.82, 'massive_boost_29', 'system'),
('LINKEDIN_CONTENT: Les lecons apprises (j ai echoue a X, voici ce que j ai appris) sont les posts les plus engageants.', 'LinkedIn echec + lecon = posts les plus engageants', 'content', 'insight', 0.85, 'massive_boost_29', 'system'),
('LINKEDIN_CONTENT: Le format liste (5 choses que j aurais aime savoir avant de X) est systematiquement performant.', 'LinkedIn format liste 5 choses = systematiquement performant', 'content', 'best_practice', 0.82, 'massive_boost_29', 'system'),
('LINKEDIN_CONTENT: Les posts avec data personnelle (mon CA est passe de X a Y en Z mois) generent le plus de saves.', 'LinkedIn data personnelle CA = plus de saves', 'content', 'insight', 0.82, 'massive_boost_29', 'system'),
('LINKEDIN_CONTENT: Le personal CTA (commentez OUI si vous voulez le template) genere 3x plus de commentaires et de reach.', 'LinkedIn CTA commentez OUI = 3x commentaires + reach', 'content', 'best_practice', 0.80, 'massive_boost_29', 'system'),
('BLOG_SEO: La longueur optimale d un article de blog pour le SEO: 1500-2500 mots. Pas plus long que necessaire.', 'Blog SEO: 1500-2500 mots optimal', 'seo', 'best_practice', 0.85, 'massive_boost_29', 'system'),
('BLOG_SEO: Le title tag (H1) doit contenir le mot-cle principal dans les 60 premiers caracteres.', 'Title tag H1: mot-cle dans 60 premiers chars', 'seo', 'best_practice', 0.88, 'massive_boost_29', 'system'),
('BLOG_SEO: La meta description (155-160 chars) doit contenir le mot-cle + un CTA pour maximiser le CTR SERP.', 'Meta desc: 155-160 chars + mot-cle + CTA', 'seo', 'best_practice', 0.88, 'massive_boost_29', 'system'),
('BLOG_SEO: Les images avec alt text descriptif + mot-cle augmentent le trafic Image Search de 20%.', 'Alt text image + mot-cle = +20% trafic Image Search', 'seo', 'best_practice', 0.82, 'massive_boost_29', 'system'),
('BLOG_SEO: Le internal linking (3-5 liens internes par article) augmente le page authority et le temps sur site.', 'Internal linking 3-5/article = page authority + temps site', 'seo', 'best_practice', 0.85, 'massive_boost_29', 'system'),
('BLOG_SEO: La table des matieres (TOC) dans les articles longs augmente les chances d apparaitre en featured snippet.', 'TOC articles longs = chances featured snippet', 'seo', 'best_practice', 0.82, 'massive_boost_29', 'system'),
('ADS_BUDGET: Le budget pub minimum pour avoir des resultats significatifs: 500€/mois Meta, 500€/mois Google.', 'Budget pub min: 500€/mois Meta + 500€/mois Google', 'ads', 'best_practice', 0.82, 'massive_boost_29', 'system'),
('ADS_BUDGET: Le split budget recommande: 60% Meta (awareness + conversion), 30% Google (intent), 10% test (TikTok, LinkedIn).', 'Split budget: 60% Meta, 30% Google, 10% test', 'ads', 'best_practice', 0.80, 'massive_boost_29', 'system'),
('ADS_BUDGET: Ne jamais couper une campagne rentable pour economiser. Le ROAS positif = investir plus, pas moins.', 'ROAS positif = investir plus pas moins', 'ads', 'best_practice', 0.88, 'massive_boost_29', 'system'),
('ADS_BUDGET: Le scaling vertical (augmenter le budget de 20%/jour max) est plus stable que le scaling horizontal (dupliquer les ad sets).', 'Scaling vertical +20%/jour > horizontal duplication', 'ads', 'best_practice', 0.82, 'massive_boost_29', 'system'),
('ADS_BUDGET: Le seuil de rentabilite publicitaire: quand le CPA < LTV. Calculer avant de lancer toute campagne.', 'Seuil rentabilite: CPA < LTV. Calculer avant lancement', 'ads', 'best_practice', 0.88, 'massive_boost_29', 'system'),
('GMAPS_STRATEGY: Repondre a un avis negatif avec empathie et solution concrete transforme 30% des mecontents en ambassadeurs.', 'Avis negatif: empathie + solution = 30% ambassadeurs', 'gmaps', 'best_practice', 0.85, 'massive_boost_29', 'system'),
('GMAPS_STRATEGY: Demander un avis a chaud (5 minutes apres la prestation) a un taux de conversion de 40% vs 5% par email.', 'Demande avis a chaud 5 min = 40% vs 5% email', 'gmaps', 'insight', 0.85, 'massive_boost_29', 'system'),
('GMAPS_STRATEGY: Le QR code vers la page Google pour laisser un avis simplifie le processus et augmente les avis de 25%.', 'QR code avis Google = +25% avis', 'gmaps', 'best_practice', 0.82, 'massive_boost_29', 'system'),
('GMAPS_STRATEGY: Les Google Posts avec CTA (Reserver, Appeler, En savoir plus) generent 50% plus de clics que ceux sans CTA.', 'Google Posts + CTA = +50% clics', 'gmaps', 'insight', 0.82, 'massive_boost_29', 'system'),
('GMAPS_STRATEGY: La completude du profil (horaires, services, photos, description) augmente les chances du pack local de 70%.', 'Profil GMB complet = +70% pack local', 'gmaps', 'best_practice', 0.85, 'massive_boost_29', 'system'),
('COMMERCIAL_PROCESS: Le discovery call (appel de decouverte de 30 min) est l etape la plus critique du cycle de vente.', 'Discovery call 30 min = etape critique cycle vente', 'commercial', 'best_practice', 0.85, 'massive_boost_29', 'system'),
('COMMERCIAL_PROCESS: Les questions ouvertes (comment, pourquoi, qu est-ce qui) revelent les vrais besoins. Eviter les questions fermees.', 'Questions ouvertes = vrais besoins. Eviter fermees', 'commercial', 'best_practice', 0.85, 'massive_boost_29', 'system'),
('COMMERCIAL_PROCESS: Le recap email apres chaque appel (ce qui a ete dit + prochaines etapes) augmente le taux de closing de 20%.', 'Recap email post-call = +20% closing', 'commercial', 'best_practice', 0.82, 'massive_boost_29', 'system'),
('COMMERCIAL_PROCESS: La proposition commerciale doit etre envoyee dans les 24h apres le call. Apres 48h la motivation baisse de 40%.', 'Proposition < 24h post-call. > 48h = -40% motivation', 'commercial', 'best_practice', 0.85, 'massive_boost_29', 'system'),
('COMMERCIAL_PROCESS: Le pipeline review hebdomadaire (30 min) avec l equipe aligne les priorites et detecte les deals a risque.', 'Pipeline review hebdo 30 min = priorites + deals a risque', 'commercial', 'best_practice', 0.82, 'massive_boost_29', 'system'),
('COMPTABILITE_TIPS: Le compte pro dedie (separe du perso) est obligatoire pour les societes et recommande pour les auto-entrepreneurs.', 'Compte pro dedie: obligatoire societes, recommande auto', 'comptable', 'best_practice', 0.88, 'massive_boost_29', 'system'),
('COMPTABILITE_TIPS: Les logiciels de facturation certifies (Facture.net, Axonaut, Pennylane) sont obligatoires depuis 2018 en France.', 'Facturation certifiee obligatoire FR depuis 2018', 'comptable', 'best_practice', 0.85, 'massive_boost_29', 'system'),
('COMPTABILITE_TIPS: Le rapprochement bancaire mensuel detecte les erreurs et les fraudes. Ne jamais sauter un mois.', 'Rapprochement bancaire mensuel = detecter erreurs/fraudes', 'comptable', 'best_practice', 0.85, 'massive_boost_29', 'system'),
('COMPTABILITE_TIPS: Les factures doivent etre emises dans les 15 jours apres la prestation (obligation legale FR).', 'Factures: 15 jours max apres prestation FR', 'comptable', 'best_practice', 0.85, 'massive_boost_29', 'system'),
('COMPTABILITE_TIPS: Le BFR (Besoin en Fonds de Roulement) doit etre surveille. Un BFR negatif = le business finance son fonctionnement.', 'BFR: surveiller. Negatif = auto-financement', 'comptable', 'insight', 0.82, 'massive_boost_29', 'system'),
('RH_RECRUTEMENT: L offre d emploi ideale: mission + competences requises + avantages + fourchette salariale + process. En 1 page.', 'Offre emploi: mission + competences + avantages + salaire + process. 1 page', 'rh', 'best_practice', 0.82, 'massive_boost_29', 'system'),
('RH_RECRUTEMENT: Les tests techniques (coding challenge, case study) predisent la performance 3x mieux que les entretiens classiques.', 'Tests techniques = 3x meilleur predictor vs entretien', 'rh', 'insight', 0.82, 'massive_boost_29', 'system'),
('RH_RECRUTEMENT: La diversite dans les equipes augmente l innovation de 20% et la performance financiere de 15%.', 'Diversite equipe = +20% innovation +15% finance', 'rh', 'insight', 0.80, 'massive_boost_29', 'system'),
('RH_RECRUTEMENT: Le employee referral program (prime pour les employes qui recommandent) est le canal de recrutement #1 en qualite.', 'Employee referral = canal recrutement #1 qualite', 'rh', 'best_practice', 0.82, 'massive_boost_29', 'system'),
('RH_RECRUTEMENT: Le time-to-hire ideal: < 3 semaines. Au-dela les meilleurs candidats acceptent d autres offres.', 'Time-to-hire < 3 semaines. Sinon perte meilleurs candidats', 'rh', 'insight', 0.82, 'massive_boost_29', 'system')
INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('THREAD_HOOKS: "J ai genere X€ en Y jours. Voici ma methode en Z etapes:" combine resultat + methode = irresistible.', 'Hook resultat+methode = irresistible', 'content', 'best_practice', 0.85, 'massive_boost_30', 'system'),
('THREAD_HOOKS: "Personne ne parle de X (et c est un probleme)" cree de la curiosite + le sentiment d information exclusive.', 'Hook personne ne parle de X = curiosite + exclusivite', 'content', 'best_practice', 0.82, 'massive_boost_30', 'system'),
('THREAD_HOOKS: "J ai analyse X [entreprises/comptes/strategies] et voici ce que j ai trouve:" positionne comme expert data-driven.', 'Hook analyse X = expert data-driven', 'content', 'best_practice', 0.82, 'massive_boost_30', 'system'),
('EMAIL_SUBJECT: "Re: notre conversation" a un taux d ouverture de 45% car il simule une reponse (utiliser avec ethique).', 'Subject Re: conversation = 45% OR (ethique)', 'email', 'insight', 0.75, 'massive_boost_30', 'system'),
('EMAIL_SUBJECT: "[Prenom], une question rapide" combine personnalisation + curiosite = 35% OR.', 'Subject Prenom+question rapide = 35% OR', 'email', 'insight', 0.82, 'massive_boost_30', 'system'),
('EMAIL_SUBJECT: Les chiffres dans le subject ("3 erreurs", "5 astuces") augmentent l OR de 15%.', 'Chiffres dans subject = +15% OR', 'email', 'insight', 0.82, 'massive_boost_30', 'system'),
('EMAIL_SUBJECT: La ponctuation dans le subject: l interrogation augmente l OR, l exclamation la reduit (spam signal).', 'Subject: ? = +OR, ! = -OR (spam)', 'email', 'insight', 0.78, 'massive_boost_30', 'system'),
('CONVERSION_COPYWRITING: Le before/after/bridge (BAB) est le framework de copy le plus rapide a ecrire et le plus efficace.', 'BAB = framework copy le plus rapide + efficace', 'content', 'best_practice', 0.85, 'massive_boost_30', 'system'),
('CONVERSION_COPYWRITING: Les mots sensoriels (sentir, voir, toucher, gouter, entendre) augmentent l immersion de 30%.', 'Mots sensoriels = +30% immersion', 'content', 'insight', 0.78, 'massive_boost_30', 'system'),
('CONVERSION_COPYWRITING: Le present continu (vous etes en train de...) est plus immersif que le futur (vous allez...).', 'Present continu > futur pour immersion', 'content', 'best_practice', 0.78, 'massive_boost_30', 'system'),
('AI_AGENTS: Les agents IA doivent avoir un scope defini (1 agent = 1 domaine) pour eviter les hallucinations hors-sujet.', 'Agent IA: 1 domaine par agent = moins hallucinations', 'ceo', 'best_practice', 0.92, 'massive_boost_30', 'system'),
('AI_AGENTS: Le contexte injecte dans le prompt doit etre recent (< 7 jours) pour eviter les recommandations obsoletes.', 'Contexte agent < 7 jours pour eviter obsolescence', 'ceo', 'best_practice', 0.85, 'massive_boost_30', 'system'),
('AI_AGENTS: Les agents doivent avoir un mode explain (expliquer leurs decisions) pour la transparence avec le client.', 'Agents mode explain = transparence client', 'ceo', 'best_practice', 0.85, 'massive_boost_30', 'system'),
('AI_AGENTS: Le fallback humain (escalader a un humain quand l agent n est pas sur) est essentiel pour la confiance.', 'Fallback humain agent = essentiel confiance', 'ceo', 'best_practice', 0.90, 'massive_boost_30', 'system'),
('AI_AGENTS: Les agents doivent apprendre des corrections du client (feedback loop) pour s ameliorer dans le temps.', 'Feedback loop client → agent amelioration continue', 'ceo', 'best_practice', 0.90, 'massive_boost_30', 'system'),
('AI_AGENTS: Le rate limiting des agents (max X actions/heure) previent les spam et les couts excessifs.', 'Rate limiting agents = prevenir spam + couts', 'ceo', 'best_practice', 0.88, 'massive_boost_30', 'system'),
('AI_AGENTS: Les agents multi-modaux (texte + image + audio) seront le standard en 2027. Se preparer des maintenant.', 'Agents multi-modaux = standard 2027. Preparer', 'ceo', 'insight', 0.78, 'massive_boost_30', 'system'),
('AI_AGENTS: Le CEO agent doit avoir une vue holistique de tous les agents et de leurs performances pour coordonner.', 'CEO agent = vue holistique coordination tous agents', 'ceo', 'best_practice', 0.92, 'massive_boost_30', 'system'),
('AI_AGENTS: Les agents de contenu doivent respecter le brand voice defini dans le dossier client. Jamais de deviation.', 'Agents contenu = brand voice dossier client. 0 deviation', 'content', 'best_practice', 0.92, 'massive_boost_30', 'system'),
('AI_AGENTS: Les agents commerciaux doivent prioriser les prospects chauds (score > 60) et ne jamais spammer les froids.', 'Agents commerciaux: prospects chauds > 60. Jamais spam froids', 'commercial', 'best_practice', 0.90, 'massive_boost_30', 'system'),
('SECTEUR_SANTE: Le contenu medical doit citer ses sources (etudes, institutions). Pas de conseils medicaux sans reference.', 'Contenu medical: citer sources. Pas conseil sans reference', NULL, 'best_practice', 0.90, 'massive_boost_30', 'system'),
('SECTEUR_SANTE: Les praticiens qui publient des contenus educatifs sur les reseaux voient leur cabinet remplir 40% plus vite.', 'Praticiens contenu educatif = +40% remplissage cabinet', NULL, 'insight', 0.80, 'massive_boost_30', 'system'),
('SECTEUR_JURIDIQUE: Les cabinets d avocats qui bloguent sur des sujets courants (divorce, succession, droit du travail) captent 50% de leads en plus.', 'Blog juridique sujets courants = +50% leads avocats', NULL, 'insight', 0.80, 'massive_boost_30', 'system'),
('SECTEUR_EDUCATION: Les ecoles privees qui investissent dans le branding (site, reseaux, temoignages) augmentent leurs inscriptions de 30%.', 'Branding ecole privee = +30% inscriptions', NULL, 'insight', 0.78, 'massive_boost_30', 'system'),
('SECTEUR_TECH: Les startups tech qui publient du contenu technique (blog engineering) attirent les meilleurs talents dev.', 'Blog engineering tech = attirer meilleurs devs', NULL, 'insight', 0.82, 'massive_boost_30', 'system'),
('SECTEUR_ARTISANAT: Les artisans qui montrent le processus de fabrication en video ont un taux d engagement 5x superieur.', 'Artisanat video processus = 5x engagement', NULL, 'insight', 0.82, 'massive_boost_30', 'system'),
('SECTEUR_IMMO: Les agents immobiliers qui publient des market updates mensuels sont percus comme experts de confiance.', 'Agent immo market updates mensuels = expert confiance', NULL, 'insight', 0.80, 'massive_boost_30', 'system'),
('SECTEUR_FINANCE: Le contenu finance doit inclure un disclaimer (ceci n est pas un conseil financier) pour la conformite.', 'Contenu finance: disclaimer obligatoire', NULL, 'best_practice', 0.88, 'massive_boost_30', 'system'),
('SECTEUR_SPORT: Les salles de sport qui creent des challenges mensuels avec classement ont 2x plus de retention.', 'Challenges mensuels salle sport = 2x retention', NULL, 'insight', 0.80, 'massive_boost_30', 'system'),
('SECTEUR_VOYAGE: Les agences de voyage qui proposent des experiences immersives (VR, videos 360) augmentent les reservations de 25%.', 'Agence voyage VR/360 = +25% reservations', NULL, 'insight', 0.78, 'massive_boost_30', 'system'),
('SECTEUR_ALIMENTATION: Les marques alimentaires avec storytelling (origine, producteur, recette) vendent 40% plus cher.', 'Food storytelling origine/producteur = +40% prix', NULL, 'insight', 0.80, 'massive_boost_30', 'system'),
('SECTEUR_MODE: Le live shopping est le format de conversion #1 pour la mode en ligne en 2026.', 'Live shopping = #1 conversion mode online 2026', NULL, 'insight', 0.78, 'massive_boost_30', 'system'),
('SECTEUR_BEAUTE: Les tutoriels step-by-step avec le produit augmentent les ventes de 45%.', 'Tuto step-by-step beaute = +45% ventes', NULL, 'insight', 0.82, 'massive_boost_30', 'system'),
('SECTEUR_AUTOMOBILE: Le configurateur 3D en ligne augmente le temps d engagement de 5x et les demandes d essai de 30%.', 'Configurateur 3D auto = 5x engagement +30% essais', NULL, 'insight', 0.78, 'massive_boost_30', 'system'),
