INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('AFFILIATION_AVANCE: Le cookie de tracking affiliation doit durer 30-90 jours. 7 jours est trop court pour les cycles B2B.', 'Cookie affiliation 30-90j. 7j trop court B2B', 'marketing', 'best_practice', 0.80, 'massive_boost_31', 'system'),
('AFFILIATION_AVANCE: Les affilies doivent avoir acces a des creatives (bannieres, emails, landing pages) pour maximiser les conversions.', 'Affilies = acces creatives pour max conversion', 'marketing', 'best_practice', 0.82, 'massive_boost_31', 'system'),
('AFFILIATION_AVANCE: La commission recurring (% chaque mois tant que le client reste) motive 3x plus que la commission one-shot.', 'Commission recurring affiliation = 3x motivation vs one-shot', 'marketing', 'insight', 0.82, 'massive_boost_31', 'system'),
('REFERRAL_PROGRAM: Le programme parrainage ideal: recompense parrain ET filleul. 1 mois gratuit chacun est le standard SaaS.', 'Referral SaaS: 1 mois gratuit parrain + filleul', 'marketing', 'best_practice', 0.85, 'massive_boost_31', 'system'),
('REFERRAL_PROGRAM: Le moment de demander un referral: apres un succes client (pas apres un bug ou une plainte).', 'Referral: demander apres succes, jamais apres probleme', 'marketing', 'best_practice', 0.88, 'massive_boost_31', 'system'),
('REFERRAL_PROGRAM: Le lien de parrainage unique + tracking automatique + notification = taux de participation de 10-15%.', 'Lien referral unique + tracking + notif = 10-15% participation', 'marketing', 'insight', 0.82, 'massive_boost_31', 'system'),
('REFERRAL_PROGRAM: Les meilleurs ambassadeurs sont les clients avec NPS 9-10. Les identifier et les contacter directement.', 'Ambassadeurs = clients NPS 9-10. Contacter directement', 'marketing', 'best_practice', 0.85, 'massive_boost_31', 'system'),
('MARKETPLACE_TIPS: Le onboarding vendeur doit etre < 10 minutes. Chaque minute de plus perd 15% des inscriptions.', 'Onboarding vendeur marketplace < 10 min. +1 min = -15%', NULL, 'insight', 0.80, 'massive_boost_31', 'system'),
('MARKETPLACE_TIPS: Le escrow (paiement sequestre) est obligatoire pour la confiance. Le vendeur est paye apres la livraison.', 'Escrow marketplace: paiement apres livraison', NULL, 'best_practice', 0.85, 'massive_boost_31', 'system'),
('MARKETPLACE_TIPS: Le review system bilateral (acheteur note vendeur ET vendeur note acheteur) ameliore la qualite des 2 cotes.', 'Reviews bilaterales marketplace = qualite 2 cotes', NULL, 'best_practice', 0.82, 'massive_boost_31', 'system'),
('SUBSCRIPTION_BOX: Le churn des subscription boxes: 10-15% mensuel en moyenne. La surprise et la nouveaute sont cles.', 'Subscription box churn: 10-15%/mois. Surprise = cle', NULL, 'insight', 0.78, 'massive_boost_31', 'system'),
('SUBSCRIPTION_BOX: Le unboxing experience (packaging, presentation, note) augmente les partages sociaux de 40%.', 'Unboxing experience = +40% partages sociaux', NULL, 'insight', 0.80, 'massive_boost_31', 'system'),
('D2C: Le Direct-to-Consumer elimine les intermediaires. Marge 2-3x superieure au wholesale.', 'D2C: 2-3x marge vs wholesale', NULL, 'insight', 0.82, 'massive_boost_31', 'system'),
('D2C: Les marques D2C qui reussissent: brand story forte + communaute + experience client premium.', 'D2C succes: brand story + communaute + experience premium', NULL, 'insight', 0.82, 'massive_boost_31', 'system'),
('D2C: Le CAC pour les marques D2C en 2026: 30-80€ via Meta Ads, 10-30€ via content + referral.', 'D2C CAC: Meta 30-80€, content+referral 10-30€', NULL, 'insight', 0.78, 'massive_boost_31', 'system'),
('NEWSLETTER_MONETIZATION: Les newsletters avec 10K+ abonnes peuvent generer 500-5000€/mois en sponsoring.', 'Newsletter 10K+ abonnes = 500-5000€/mois sponsoring', 'email', 'insight', 0.78, 'massive_boost_31', 'system'),
('NEWSLETTER_MONETIZATION: Le CPM (cout pour 1000 emails) pour le sponsoring newsletter: 20-50€ pour les newsletters de qualite.', 'Newsletter sponsoring CPM: 20-50€ qualite', 'email', 'insight', 0.75, 'massive_boost_31', 'system'),
('NEWSLETTER_MONETIZATION: Les liens affilies dans les newsletters generent 5-15% de revenus supplementaires sans effort.', 'Liens affilies newsletter = 5-15% revenus supplementaires', 'email', 'insight', 0.78, 'massive_boost_31', 'system'),
('CONTENT_REPURPOSING: 1 article de blog → 10 posts sociaux + 5 tweets + 3 emails + 1 video resume + 1 infographie.', '1 article = 10 posts + 5 tweets + 3 emails + 1 video + 1 infographie', 'content', 'best_practice', 0.85, 'massive_boost_31', 'system'),
